#include <Wire.h>
#include <SPI.h>

#define INA_SOLAR  0x40
#define INA_BATT   0x41
#define INA_CFG    0x00
#define INA_SHUNT  0x01
#define INA_BUS    0x02
#define IMU_CS     10
#define ICM_AZ_H   0x23
#define MPPT_PWM   9
#define LOAD_EN    8
#define FAULT_LED  7

#define BATT_MIN   6.5f
#define BATT_MAX   8.4f
#define SOL_MAX_I  1.5f
#define LOG_MS     1000

float kp=2.0f,ki=0.1f,kd=0.5f;
float pid_int=0,pid_prev=0;
uint8_t duty=128;
float prev_pwr=0;
int   ddir=1;
unsigned long last_log=0;
bool fault=false;

void ina_wr(uint8_t a,uint8_t r,uint16_t v){
  Wire.beginTransmission(a);
  Wire.write(r);Wire.write(v>>8);Wire.write(v&0xFF);
  Wire.endTransmission();
}
float ina_bus(uint8_t a){
  Wire.beginTransmission(a);Wire.write(INA_BUS);Wire.endTransmission(false);
  Wire.requestFrom(a,(uint8_t)2);
  uint16_t r=((uint16_t)Wire.read()<<8)|Wire.read();
  return (r>>3)*0.004f;
}
float ina_shunt(uint8_t a){
  Wire.beginTransmission(a);Wire.write(INA_SHUNT);Wire.endTransmission(false);
  Wire.requestFrom(a,(uint8_t)2);
  int16_t r=(int16_t)(((uint16_t)Wire.read()<<8)|Wire.read());
  return r*0.00001f;
}
float imu_az(){
  SPI.beginTransaction(SPISettings(8000000,MSBFIRST,SPI_MODE0));
  digitalWrite(IMU_CS,LOW);
  SPI.transfer(0x80|ICM_AZ_H);
  uint8_t h=SPI.transfer(0),l=SPI.transfer(0);
  digitalWrite(IMU_CS,HIGH);SPI.endTransaction();
  return (int16_t)((h<<8)|l)/2048.0f;
}
void mppt_po(float pwr){
  float dp=pwr-prev_pwr;
  if(dp>0) duty=(uint8_t)constrain(duty+ddir,10,245);
  else{ddir=-ddir;duty=(uint8_t)constrain(duty+ddir,10,245);}
  prev_pwr=pwr;
  analogWrite(MPPT_PWM,duty);
}
float pid_step(float err,float dt){
  pid_int=constrain(pid_int+err*dt,-100.0f,100.0f);
  float d=(err-pid_prev)/dt;pid_prev=err;
  return kp*err+ki*pid_int+kd*d;
}
bool chk_fault(float bv,float si){
  if(bv<BATT_MIN){Serial.println("FAULT:LOW_BATT");return true;}
  if(bv>BATT_MAX){Serial.println("FAULT:OVERVOLT");return true;}
  if(si>SOL_MAX_I){Serial.println("FAULT:OVERCURR");return true;}
  return false;
}
void setup(){
  Serial.begin(115200);
  Wire.begin();SPI.begin();
  pinMode(IMU_CS,OUTPUT);digitalWrite(IMU_CS,HIGH);
  pinMode(MPPT_PWM,OUTPUT);
  pinMode(LOAD_EN,OUTPUT);digitalWrite(LOAD_EN,HIGH);
  pinMode(FAULT_LED,OUTPUT);
  ina_wr(INA_SOLAR,INA_CFG,0x3FFF);
  ina_wr(INA_BATT, INA_CFG,0x3FFF);
  analogWrite(MPPT_PWM,duty);
  Serial.println("t_ms,sv,si,sp,bv,bi,az,duty,fault");
}
void loop(){
  static unsigned long pt=0;
  unsigned long now=millis();
  float dt=(now-pt)/1000.0f;
  if(dt<0.05f)return;
  pt=now;
  float sv=ina_bus(INA_SOLAR),si=ina_shunt(INA_SOLAR),sp=sv*si;
  float bv=ina_bus(INA_BATT), bi=ina_shunt(INA_BATT);
  float az=imu_az();
  fault=chk_fault(bv,si);
  digitalWrite(FAULT_LED,(uint8_t)fault);
  if(!fault){
    mppt_po(sp);
    int tpwm=constrain((int)(127.0f+pid_step(0.5f-az,dt)*20.0f),0,255);
    (void)tpwm;
    digitalWrite(LOAD_EN,HIGH);
  } else {
    digitalWrite(LOAD_EN,LOW);
    analogWrite(MPPT_PWM,64);
    pid_int=0;
  }
  if(now-last_log>=LOG_MS){
    last_log=now;
    Serial.print(now);Serial.print(',');
    Serial.print(sv,3);Serial.print(',');
    Serial.print(si,4);Serial.print(',');
    Serial.print(sp,4);Serial.print(',');
    Serial.print(bv,3);Serial.print(',');
    Serial.print(bi,4);Serial.print(',');
    Serial.print(az,4);Serial.print(',');
    Serial.print(duty);Serial.print(',');
    Serial.println(fault?1:0);
  }
}
